  denom_fpr.full <- sum(1-yhat.full)
  num_tpr.full <- numeric(length(c))
  num_fpr.full <- numeric(length(c))
  for (j in 1:length(c)){
    ind <- (yhat.full>=c[j])
    num_tpr.full[j] <- sum(yhat.full[ind==1])
    num_fpr.full[j] <- sum((1-yhat.full)[ind==1])
  }
  tpr.full <- num_tpr.full/denom_tpr.full
  fpr.full <- num_fpr.full/denom_fpr.full
  auc <- auc(fpr.full, tpr.full)
  
  # numerical method for dFPR/dbeta and dTPR/dbeta as a function of c
  dFPR_beta <- matrix(0, nrow=numbeta, ncol=length(c))
  dTPR_beta <- matrix(0, nrow=numbeta, ncol=length(c))
  yfit1 <- numeric(nrow(data))
  yfit2 <- numeric(nrow(data))
  for (i in 1:numbeta){
    tmp1 <- beta.full
    tmp2 <- beta.full
    tmp1[i] <- beta.full[i] + epsilon_beta[i]
    tmp2[i] <- beta.full[i] - epsilon_beta[i]
    yfit1 <- exp(X %*% tmp1)/(1 + exp(X %*% tmp1))
    yfit2 <-  exp(X %*% tmp2)/(1 + exp(X %*% tmp2))
    num1_tpr <- 0
    num2_tpr <- 0
    num1_fpr <- 0
    num2_fpr <- 0
    denom1_tpr <- sum(yfit1)
    denom2_tpr <- sum(yfit2)
    denom1_fpr <- sum(1-yfit1)
    denom2_fpr <- sum(1-yfit2)
    
    for (j in 1:length(c)){
      ind1 <- (yfit1>=c[j])
      ind2 <- (yfit2>=c[j])
      num1_tpr <- sum(yfit1[ind1==1])
      num2_tpr <- sum(yfit2[ind2==1])
      num1_fpr <- sum((1-yfit1)[ind1==1])
      num2_fpr <- sum((1-yfit2)[ind2==1])
      dTPR_beta[i,j] <- (num1_tpr/denom1_tpr-num2_tpr/denom2_tpr)/(2*epsilon_beta[i])
      dFPR_beta[i,j] <- (num1_fpr/denom1_fpr-num2_fpr/denom2_fpr)/(2*epsilon_beta[i])
    }
  }
  
  # calculate influence function for TPR/FPR as a function of c
  mat_tpr.full <- matrix(0, nrow=nrow(data), ncol=length(c))
  mat_fpr.full <- matrix(0, nrow=nrow(data), ncol=length(c))
  for (j in 1:length(c)){
    ind <- (yhat.full>=c[j])
    mat_tpr.full[,j] <- yhat.full*(ind-tpr.full[j])/(denom_tpr.full/n)
    mat_fpr.full[,j] <- (1-yhat.full)*(ind-fpr.full[j])/(denom_fpr.full/n)
  }
  
  # CORRECTED: calculate the influence function for tpr/fpr using h_beta_all
  h_tpr <- t(h_beta_all) %*% dTPR_beta + mat_tpr.full
  h_fpr <- t(h_beta_all) %*% dFPR_beta + mat_fpr.full
  
  # Separate influence functions for cases and controls
  h1_tpr <- h_tpr[data$y == 1, ]
  h0_tpr <- h_tpr[data$y == 0, ]
  h1_fpr <- h_fpr[data$y == 1, ]
  h0_fpr <- h_fpr[data$y == 0, ]
  
  #calcualte influence function for auc
  h1_auc <- 0-apply(h1_fpr, 1, function(x) auc(tpr.full, x))+apply(h1_tpr, 1, function(x) auc(fpr.full, x))
  h0_auc <- 0-apply(h0_fpr, 1, function(x) auc(tpr.full, x))+apply(h0_tpr, 1, function(x) auc(fpr.full, x))
  
  # CORRECTED: calculate variance of AUC
  h_auc_full <- rep(NA, n)
  h_auc_full[data$y == 1] <- h1_auc
  h_auc_full[data$y == 0] <- h0_auc
  var_auc <- var(h_auc_full) / n
  
  return(list(auc=auc, sq_var_auc=sqrt(var_auc)))
}

calculate_expectation_tps <- function(mle_fit_list, data_list, cond_Y) {
  # 从列表中提取所需对象
  beta_model <- mle_fit_list$beta.mle
  yhat_model <- mle_fit_list$yhat.mle# 预测概率 p_hat
  fhat_model <- mle_fit_list$f.mle # 分布函数 dF_hat
  df_dbeta_model <- mle_fit_list$df_beta
  h1_model <- mle_fit_list$h1
  h2_model <- mle_fit_list$h2
  num_beta <- length(beta_model)
  dat2_mle_df <- data_list$dat2.mle
  n_total_phaseI <- nrow(data_list$dat)
  # 1. 计算期望值 E[p|Y=cond_Y]
  p1_cond <- if (cond_Y == 1) yhat_model else (1 - yhat_model)
  denominator_E <- sum(p1_cond * fhat_model)
  numerator_E <- sum(yhat_model * p1_cond * fhat_model)
  E_val <- if (denominator_E != 0) numerator_E / denominator_E else 0
  # 2. 数值计算 ∂E/∂β
  dE_dbeta_val <- numeric(num_beta)
  epsilon_beta <- abs(beta_model) / 1e4
  epsilon_beta[epsilon_beta == 0] <- 1e-6
  # 动态确定公式和设计矩阵
  model_formula <- if (num_beta == 5) as.formula("~ x1 + x2 + x3 + z") else as.formula("~ x1 + x2 + x3")
  XX2_model <- model.matrix(model_formula, data = dat2_mle_df)
  for (j in 1:num_beta) {
    beta_plus <- beta_model; beta_plus[j] <- beta_plus[j] + epsilon_beta[j]
    beta_minus <- beta_model; beta_minus[j] <- beta_minus[j] - epsilon_beta[j]
    yhat_plus <- as.vector(1 / (1 + exp(-XX2_model %*% beta_plus)))
    yhat_minus <- as.vector(1 / (1 + exp(-XX2_model %*% beta_minus)))
    fhat_plus <- fhat_model + df_dbeta_model[j,] * epsilon_beta[j]
    fhat_minus <- fhat_model - df_dbeta_model[j,] * epsilon_beta[j]
    p1_plus_cond <- if (cond_Y == 1) yhat_plus else (1 - yhat_plus)
    p1_minus_cond <- if (cond_Y == 1) yhat_minus else (1 - yhat_minus)
    E_plus <- sum(yhat_plus * p1_plus_cond * fhat_plus) / sum(p1_plus_cond * fhat_plus)
    E_minus <- sum(yhat_minus * p1_minus_cond * fhat_minus) / sum(p1_minus_cond * fhat_minus)
    dE_dbeta_val[j] <- (E_plus - E_minus) / (2 * epsilon_beta[j])
  }
  # 3a. 获取 h1_model (对beta的影响) 的列结构，它与 (Y, G) 组合对应
  dat11_mle_info <- plyr::count(data_list$dat, vars = c("y", "G"))
  
  # 3b. 计算每个 (Y, G) 组合对期望 E 的总体影响
  H_E_by_group <- as.vector(t(h1_model) %*% dE_dbeta_val)
  
  # 3c. 创建一个 2xG 的矩阵来结构化地存储这些分层影响函数，以便后续查找
  numG <- length(data_list$nn1) # 从 data_list 获取分层数量
  H_E_phase1_stratified <- matrix(NA, 
                                  nrow = 2, 
                                  ncol = numG, 
                                  dimnames = list(c("Y=0", "Y=1"), paste0("G=", 1:numG)))
  
  # 3d. 根据 (Y,G) 组合的结构，填充这个矩阵
  for (i in 1:nrow(dat11_mle_info)) {
    y_val <- dat11_mle_info[i, "y"]
    g_val <- dat11_mle_info[i, "G"]
    # y=0 对应矩阵第1行, y=1 对应第2行
    H_E_phase1_stratified[y_val + 1, g_val] <- H_E_by_group[i]
  }
  
  # 3. 计算与分布函数相关的直接影响 φ_F
  phi_F_E_val <- numeric(length(yhat_model))
  if (denominator_E != 0) {
    phi_F_E_val <- (fhat_model * n_total_phaseI / denominator_E) * p1_cond * (yhat_model - E_val)
  }
  # 4. 组合得到该期望值的影响函数 (分为Phase I only 和 Phase II 两部分)
  H_E_phase1 <- as.vector(t(h1_model) %*% dE_dbeta_val)
  H_E_phase2 <- as.vector(t(h2_model) %*% dE_dbeta_val) + phi_F_E_val
  return(list(E_val = E_val, 
              H_E_phase1_stratified = H_E_phase1_stratified, # 【修改点】现在是一个 2xG 矩阵
              H_E_phase2 = H_E_phase2))
}

calculate_expectation_glm <- function(mle_fit_list, dat_full_cohort, cond_Y) {
  # 从列表中提取所需对象
  model_glm <- mle_fit_list$model
  beta_glm <- mle_fit_list$beta.mle
  h_beta_glm <- mle_fit_list$h_beta # H_β, N x p 矩阵
  num_beta <- length(beta_glm)
  pred_risk <- predict(model_glm, type = "response")
  y_full <- dat_full_cohort$y
  n_total <- nrow(dat_full_cohort)
  # 1. 计算期望值 E[p|Y=cond_Y]
  idx_cond <- which(y_full == cond_Y)
  E_val <- mean(pred_risk[idx_cond])
  # 2. 数值计算 ∂E/∂β
  dE_dbeta_val <- numeric(num_beta)
  epsilon_beta <- abs(beta_glm) / 1e5
  epsilon_beta[epsilon_beta == 0] <- 1e-6
  X_glm <- model.matrix(model_glm)
  for (j in 1:num_beta) {
    beta_plus <- beta_glm; beta_plus[j] <- beta_plus[j] + epsilon_beta[j]
    beta_minus <- beta_glm; beta_minus[j] <- beta_minus[j] - epsilon_beta[j]
    pred_plus <- as.vector(1 / (1 + exp(-X_glm %*% beta_plus)))
    pred_minus <- as.vector(1 / (1 + exp(-X_glm %*% beta_minus)))
    E_plus <- mean(pred_plus[idx_cond])
    E_minus <- mean(pred_minus[idx_cond])
    dE_dbeta_val[j] <- (E_plus - E_minus) / (2 * epsilon_beta[j])
  }
  # === 修改开始 ===
  # 3. (已移除) 移除 phi_F0_E_val 的计算，因为其影响被排除
  # p_Y_cond <- mean(y_full == cond_Y)
  # phi_F0_E_val <- numeric(n_total)
  # if (p_Y_cond > 0) {
  #  phi_F0_E_val <- (as.integer(y_full == cond_Y) / p_Y_cond) * (pred_risk - E_val)
  # }
  
  # 4. 仅根据参数不确定性计算总影响函数
  H_E_total <- as.vector(h_beta_glm %*% dE_dbeta_val) # 移除了 "+ phi_F0_E_val"
  # === 修改结束 ===
  return(list(E_val = E_val, H_E_total = H_E_total))
}

Dat_idi_mle_final <- function(data_list, mleFit_list_new, mleFit_list_old, dat) {
  # --- 1. 提取核心对象 (此部分无变化) ---
  n_total <- nrow(dat)
  dat2_mle <- data_list$dat2.mle
  dat2_orig <- data_list$dat2_orig
  
  # --- 2. 计算新/旧模型的 IS 和 IP 及其影响函数 (此部分无变化) ---
  # 注意：这里调用的 calculate_expectation_tps 已经是我们修改后的新版本了
  IS_new_comp <- calculate_expectation_tps(mleFit_list_new, data_list, 1)
  IP_new_comp <- calculate_expectation_tps(mleFit_list_new, data_list, 0)
  
  IS_old_comp <- calculate_expectation_glm(mleFit_list_old, dat, 1)
  IP_old_comp <- calculate_expectation_glm(mleFit_list_old, dat, 0)
  
  # --- 3. 计算 IDI 估计值 (此部分无变化) ---
  IDI_est <- (IS_new_comp$E_val - IS_old_comp$E_val) - (IP_new_comp$E_val - IP_old_comp$E_val)
  
  # ======================= 【修改部分开始】 =======================
  # --- 4. 稳健地重建和组合影响函数 ---
  
  # 初始化一个N维向量用于存储总影响函数，并用ID命名以保证对齐
  H_IDI_total <- numeric(n_total)
  names(H_IDI_total) <- dat$id
  
  # 4a. 获取旧模型的总影响函数 (此部分无变化)
  H_IS_old_total <- IS_old_comp$H_E_total
  H_IP_old_total <- IP_old_comp$H_E_total
  names(H_IS_old_total) <- dat$id
  names(H_IP_old_total) <- dat$id
  
  # 4b. 新建一个N维向量用于存储新模型的总影响函数 (此部分无变化)
  H_IS_new_total <- numeric(n_total)
  H_IP_new_total <- numeric(n_total)
  names(H_IS_new_total) <- dat$id
  names(H_IP_new_total) <- dat$id
  
  # --- 【核心修改】替换原有的 4c 和 4d 逻辑 ---
  
  # 4c (新). 为 Phase-I 未抽样个体分配其分层特定的影响函数
  # 首先，识别出这些未被抽样进入 Phase II 的个体
  phase1_only_dat <- dat[!(dat$id %in% dat2_orig$id), ]
  
  # 从修改后的函数输出中获取分层影响函数矩阵
  H_IS_new_stratified <- IS_new_comp$H_E_phase1_stratified
  H_IP_new_stratified <- IP_new_comp$H_E_phase1_stratified
  
  # 遍历未抽样的个体，并根据其 Y 和 G 分配正确的影响值
  for (i in 1:nrow(phase1_only_dat)) {
    indiv_id <- as.character(phase1_only_dat$id[i])
    indiv_y  <- phase1_only_dat$y[i]
    indiv_g  <- phase1_only_dat$G[i]
    
    # y=0 对应矩阵第1行, y=1 对应第2行
    H_IS_new_total[indiv_id] <- H_IS_new_stratified[indiv_y + 1, indiv_g]
    H_IP_new_total[indiv_id] <- H_IP_new_stratified[indiv_y + 1, indiv_g]
  }
  
  # 4d (新). 为 Phase-II 抽样个体分配其影响函数
  # 这部分逻辑上是为 Phase II 个体赋值，它们的影响函数由 H_E_phase2 决定。
  # Phase-I-only 和 Phase-II 的个体是互斥的，所以可以直接赋值。
  
  # 匹配 Phase-II 的聚合数据和原始个体数据
  key_vars <- colnames(dat2_mle)[!colnames(dat2_mle) %in% c("cases", "conts")]
  dat2_mle$key <- apply(dat2_mle[, key_vars, drop = FALSE], 1, paste, collapse = "_")
  dat2_orig$key <- apply(dat2_orig[, key_vars, drop = FALSE], 1, paste, collapse = "_")
  match_indices <- match(dat2_orig$key, dat2_mle$key)
  
  if (any(is.na(match_indices))) {
    warning("并非所有 Phase-II 个体都被匹配回来计算IDI，方差可能被低估。")
    # 仅保留有效匹配以避免NA错误
    valid_orig_indices <- !is.na(match_indices)
    dat2_orig <- dat2_orig[valid_orig_indices, ]
    match_indices <- na.omit(match_indices)
  }
  
  # 将 Phase-II 个体的影响函数赋值到总影响函数向量的对应位置
  # 在 H_..._new_total 中，这些位置的值当前应为 0
  H_IS_new_total[as.character(dat2_orig$id)] <- IS_new_comp$H_E_phase2[match_indices]
  H_IP_new_total[as.character(dat2_orig$id)] <- IP_new_comp$H_E_phase2[match_indices]
  
  # --- 4e. 计算最终的IDI影响函数 (此部分无变化) ---
  H_IDI_total <- (H_IS_new_total - H_IP_new_total) - (H_IS_old_total - H_IP_old_total)
  
  # --- 5. 计算方差 (此部分无变化) ---
  var_idi <- sum(H_IDI_total^2) / (n_total^2)
  
  return(list(idi = IDI_est, var_idi = var_idi))
  # ======================= 【修改部分结束】 =======================
}



