require(plyr) # 确保 plyr 包被加载

Dat_nri_mle_final_corrected <- function(data_list, mleFit_list_new, mleFit_list_old_glm, dat_old) {
  # --- 1. 提取核心对象 (此部分无变化) ---
  dat2_mle <- data_list$dat2.mle
  dat2_orig <- data_list$dat2_orig
  n_total <- nrow(dat_old)
  
  # 新模型 (来自 tps)
  beta_new <- mleFit_list_new$beta.mle
  fhat_new <- mleFit_list_new$f.mle
  p_new <- mleFit_list_new$yhat.mle
  h1_new <- mleFit_list_new$h1
  h2_new <- mleFit_list_new$h2
  df_dbeta_new <- mleFit_list_new$df_beta
  
  # 旧模型 (来自 glm)
  beta_old <- mleFit_list_old_glm$beta.mle
  h_beta_old <- mleFit_list_old_glm$h_beta
  
  # 在与新模型相同的 Phase-II 数据点上计算旧模型的预测概率
  X_matrix_old_for_p <- model.matrix(~x1+x2+x3, dat2_mle)
  p_old <- as.vector(1/(1+exp(-X_matrix_old_for_p %*% beta_old)))
  
  # --- 2. 计算NRI点估计 (此部分无变化) ---
  is_up <- as.integer(p_new > p_old)
  is_down <- as.integer(p_new < p_old)
  
  Py1 <- sum(p_new * fhat_new)
  Py0 <- sum((1 - p_new) * fhat_new)
  
  p_up1 <- if(Py1 > 0) sum(is_up * p_new * fhat_new) / Py1 else 0
  p_down1 <- if(Py1 > 0) sum(is_down * p_new * fhat_new) / Py1 else 0
  p_up0 <- if(Py0 > 0) sum(is_up * (1 - p_new) * fhat_new) / Py0 else 0
  p_down0 <- if(Py0 > 0) sum(is_down * (1 - p_new) * fhat_new) / Py0 else 0
  
  nri_events <- p_up1 - p_down1
  nri_nonevents <- p_down0 - p_up0
  nri_est <- nri_events + nri_nonevents
  
  # --- 3. 数值计算 d(NRI)/d(beta) (此部分无变化) ---
  
  # 3a. 对新模型参数 beta_new 求导
  dNRI_dbeta_new <- numeric(length(beta_new))
  epsilon_new <- abs(beta_new)/1e9; epsilon_new[epsilon_new==0] <- 1e-9
  X_matrix_new <- model.matrix(~x1+x2+x3+z, dat2_mle)
  # ... (求导循环无变化) ...
  for(j in 1:length(beta_new)){
    b_p <- beta_new; b_p[j] <- b_p[j] + epsilon_new[j]
    b_m <- beta_new; b_m[j] <- b_m[j] - epsilon_new[j]
    fhat_p <- fhat_new + df_dbeta_new[j, ] * epsilon_new[j]
    fhat_m <- fhat_new - df_dbeta_new[j, ] * epsilon_new[j]
    p_new_p <- as.vector(1/(1+exp(-X_matrix_new %*% b_p)))
    p_new_m <- as.vector(1/(1+exp(-X_matrix_new %*% b_m)))
    is_up_p <- as.integer(p_new_p > p_old); is_down_p <- as.integer(p_new_p < p_old)
    Py1_p <- sum(p_new_p * fhat_p); Py0_p <- sum((1 - p_new_p) * fhat_p)
    p_u1_p <- if(Py1_p > 0) sum(is_up_p * p_new_p * fhat_p) / Py1_p else 0
    p_d1_p <- if(Py1_p > 0) sum(is_down_p * p_new_p * fhat_p) / Py1_p else 0
    p_u0_p <- if(Py0_p > 0) sum(is_up_p * (1 - p_new_p) * fhat_p) / Py0_p else 0
    p_d0_p <- if(Py0_p > 0) sum(is_down_p * (1 - p_new_p) * fhat_p) / Py0_p else 0
    nri_p <- (p_u1_p - p_d1_p) + (p_d0_p - p_u0_p)
    is_up_m <- as.integer(p_new_m > p_old); is_down_m <- as.integer(p_new_m < p_old)
    Py1_m <- sum(p_new_m * fhat_m); Py0_m <- sum((1 - p_new_m) * fhat_m)
    p_u1_m <- if(Py1_m > 0) sum(is_up_m * p_new_m * fhat_m) / Py1_m else 0
    p_d1_m <- if(Py1_m > 0) sum(is_down_m * p_new_m * fhat_m) / Py1_m else 0
    p_u0_m <- if(Py0_m > 0) sum(is_up_m * (1 - p_new_m) * fhat_m) / Py0_m else 0
    p_d0_m <- if(Py0_m > 0) sum(is_down_m * (1 - p_new_m) * fhat_m) / Py0_m else 0
    nri_m <- (p_u1_m - p_d1_m) + (p_d0_m - p_u0_m)
    dNRI_dbeta_new[j] <- (nri_p - nri_m) / (2 * epsilon_new[j])
  }
  
  # 3b. 对旧模型参数 beta_old 求导
  dNRI_dbeta_old <- numeric(length(beta_old))
  epsilon_old <- abs(beta_old)/1e7; epsilon_old[epsilon_old==0] <- 1e-6
  # ... (求导循环无变化) ...
  for(j in 1:length(beta_old)){
    b_p <- beta_old; b_p[j] <- b_p[j] + epsilon_old[j]
    b_m <- beta_old; b_m[j] <- b_m[j] - epsilon_old[j]
    p_old_p <- as.vector(1/(1+exp(-X_matrix_old_for_p %*% b_p)))
    p_old_m <- as.vector(1/(1+exp(-X_matrix_old_for_p %*% b_m)))
    is_up_p <- as.integer(p_new > p_old_p); is_down_p <- as.integer(p_new < p_old_p)
    is_up_m <- as.integer(p_new > p_old_m); is_down_m <- as.integer(p_new < p_old_m)
    p_u1_p <- if(Py1 > 0) sum(is_up_p * p_new * fhat_new) / Py1 else 0
    p_d1_p <- if(Py1 > 0) sum(is_down_p * p_new * fhat_new) / Py1 else 0
    p_u0_p <- if(Py0 > 0) sum(is_up_p * (1 - p_new) * fhat_new) / Py0 else 0
    p_d0_p <- if(Py0 > 0) sum(is_down_p * (1 - p_new) * fhat_new) / Py0 else 0
    nri_p <- (p_u1_p - p_d1_p) + (p_d0_p - p_u0_p)
    p_u1_m <- if(Py1 > 0) sum(is_up_m * p_new * fhat_new) / Py1 else 0
    p_d1_m <- if(Py1 > 0) sum(is_down_m * p_new * fhat_new) / Py1 else 0
    p_u0_m <- if(Py0 > 0) sum(is_up_m * (1 - p_new) * fhat_new) / Py0 else 0
    p_d0_m <- if(Py0 > 0) sum(is_down_m * (1 - p_new) * fhat_new) / Py0 else 0
    nri_m <- (p_u1_m - p_d1_m) + (p_d0_m - p_u0_m)
    dNRI_dbeta_old[j] <- (nri_p - nri_m) / (2 * epsilon_old[j])
  }
  
  # --- 4. 计算影响函数的所有组件 (此部分无变化) ---
  # a) 来自旧模型glm的影响 (对所有人)
  H_from_beta_old <- as.vector(h_beta_old %*% dNRI_dbeta_old)
  
  # b) 来自新模型tps参数的影响 (for Phase-II)
  H_from_beta_new_p2 <- as.vector(t(h2_new) %*% dNRI_dbeta_new)
  
  # c) 来自新模型非参数分布phi_F的影响
  phi_F_events <- if(Py1 > 0) (fhat_new * n_total / Py1) * p_new * ((is_up - is_down) - nri_events) else 0
  phi_F_nonevents <- if(Py0 > 0) (fhat_new * n_total / Py0) * (1 - p_new) * ((is_down - is_up) - nri_nonevents) else 0
  phi_F_NRI <- phi_F_events + phi_F_nonevents
  
  # ======================= 【修改部分开始】 =======================
  # --- 5. 稳健的N维影响函数重建 ---
  
  # 5.1 初始化总影响函数向量，并加上来自旧模型的不确定性
  H_total_nri <- numeric(n_total)
  names(H_total_nri) <- dat_old$id
  H_total_nri <- H_total_nri + H_from_beta_old
  
  # 5.2 (新) 处理来自新模型 beta_new 对 Phase-I-only 个体的影响
  # 5.2a. 计算每个(Y,G)组合对NRI的影响
  H_from_beta_new_by_group <- as.vector(t(h1_new) %*% dNRI_dbeta_new)
  
  # 5.2b. 创建一个 2xG 矩阵来结构化存储这些影响值
  dat11_info <- plyr::count(dat_old, vars = c("y", "G"))
  numG <- max(dat11_info$G)
  H_beta_new_stratified <- matrix(NA, 
                                  nrow = 2, 
                                  ncol = numG, 
                                  dimnames = list(c("Y=0", "Y=1"), paste0("G=", 1:numG)))
  
  for (i in 1:nrow(dat11_info)) {
    y_val <- dat11_info[i, "y"]
    g_val <- dat11_info[i, "G"]
    H_beta_new_stratified[y_val + 1, g_val] <- H_from_beta_new_by_group[i]
  }
  
  # 5.2c. 识别 Phase-I-only 个体
  phase1_only_dat <- dat_old[!(dat_old$id %in% dat2_orig$id), ]
  
  # 5.2d. 遍历并赋值
  for (i in 1:nrow(phase1_only_dat)) {
    indiv_id <- as.character(phase1_only_dat$id[i])
    indiv_y  <- phase1_only_dat$y[i]
    indiv_g  <- phase1_only_dat$G[i]
    
    # 加上该个体对应的、分层特定的影响值
    H_total_nri[indiv_id] <- H_total_nri[indiv_id] + H_beta_new_stratified[indiv_y + 1, indiv_g]
  }
  
  # 5.3 (新) 处理对 Phase-II 个体的影响
  # 组合来自 beta_new 和 F_hat 的影响
  H_p2_reconstructed <- H_from_beta_new_p2 + phi_F_NRI
  
  # 匹配 Phase-II 的聚合数据和原始个体数据
  key_vars <- colnames(dat2_mle)[!colnames(dat2_mle) %in% c("cases", "conts")]
  dat2_mle$key <- apply(dat2_mle[, key_vars, drop = FALSE], 1, paste, collapse = "_")
  dat2_orig$key <- apply(dat2_orig[, key_vars, drop = FALSE], 1, paste, collapse = "_")
  match_indices <- match(dat2_orig$key, dat2_mle$key)
  
  if(any(is.na(match_indices))){
    warning("并非所有 Phase-II 个体都被匹配回来计算NRI，方差可能被低估。")
    valid_indices <- !is.na(match_indices)
    dat2_orig <- dat2_orig[valid_indices, ]
    match_indices <- na.omit(match_indices)
  }
  
  # 将影响值“广播”给原始 Phase-II 个体，并加到总影响函数中
  H_p2_broadcasted <- H_p2_reconstructed[match_indices]
  H_total_nri[as.character(dat2_orig$id)] <- H_total_nri[as.character(dat2_orig$id)] + H_p2_broadcasted
  
  # --- 6. 计算方差 (此部分无变化) ---
  var_nri <- sum(H_total_nri^2) / (n_total^2)
  if (!is.na(var_nri) && var_nri > 4) {
    var_nri <- NA
  }
  return(list(nri = nri_est, var_nri = var_nri))
  # ======================= 【修改部分结束】 =======================
}

# 2.1 calculate pcf by fitting the maximum likelihood model (新增)
Dat_pcf_mle <- function(q, data_list, mleFit_list){
  #q: threshold value for calculating PCF
  #data_list: generated by Dat_format("MLE");
  fdat.mle <- data_list$fdat.mle
  dat <- data_list$dat
  dat1.mle <- data_list$dat1.mle
  dat2.mle <- data_list$dat2.mle
  
  #mleFit_list: generated by Dat_mleFit(data_list)
  fhat.mle <- mleFit_list$f.mle
  yhat.mle <- mleFit_list$yhat.mle
  beta.mle <- mleFit_list$beta.mle
  numbeta <- length(beta.mle) # 从模型中获取beta数量
  # influence function for odds ratio
  h1 <- mleFit_list$h1
  h2 <- mleFit_list$h2
  strata_mat <- mleFit_list$strata_mat
  df_beta <- mleFit_list$df_beta
  
  #calculate pcf(q)
  q.mat <- data.frame(cbind(yhat.mle, fhat.mle*n))
  names(q.mat) <- c("yhat.mle", "w")
  q.mat <- q.mat[order(-q.mat$yhat.mle),]
  quantile.mle <- cumsum(q.mat$w)/n
  indices <- which((quantile.mle<=q+0.05) & (quantile.mle>=q))
  # 处理当indices为空时的情况
  if (length(indices) == 0) {
    # 如果找不到精确匹配，可以选择最接近的值
    indices <- which.min(abs(quantile.mle - q))
  }
  p0_hat <- max(q.mat[indices, "yhat.mle"])
  
  # calculate pcf
  num_pcf <- sum((yhat.mle*fhat.mle)[yhat.mle>=p0_hat])
  denom_pcf <- sum(yhat.mle*fhat.mle)
  pcf <- num_pcf/denom_pcf
  
  # numerically calcualte dPCF/dbeta
  # 注意：epsilon_beta需要从全局环境中获取，或者作为参数传入
  dT_beta<- numeric(numbeta)
  yfit1 <- numeric(nrow(dat2.mle))
  yfit2 <- numeric(nrow(dat2.mle))
  fhat1 <- numeric(nrow(dat2.mle))
  fhat2 <- numeric(nrow(dat2.mle))
  X <- cbind(rep(1,nrow(dat2.mle)), dat2.mle$x1, dat2.mle$x2, dat2.mle$x3, dat2.mle$z) #Design matrix
  for (i in 1:numbeta){
    tmp1 <- beta.mle
    tmp2 <- beta.mle
    tmp1[i] <- beta.mle[i] + epsilon_beta[i]
    tmp2[i] <- beta.mle[i] - epsilon_beta[i]
    yfit1 <- exp(X %*% tmp1)/(1 + exp(X %*% tmp1))
    yfit2 <-  exp(X %*% tmp2)/(1 + exp(X %*% tmp2))
    fhat1 <- fhat.mle + df_beta[i,]*epsilon_beta[i]
    fhat2 <- fhat.mle - df_beta[i,]*epsilon_beta[i]
    q.mat1 <- data.frame(cbind(yfit1, fhat1*n))
    q.mat2 <- data.frame(cbind(yfit2, fhat2*n))
    names(q.mat1) <- c("yfit1", "w1")
    names(q.mat2) <- c("yfit2", "w2")
    q.mat1 <- q.mat1[order(-q.mat1$yfit1),]
    q.mat2 <- q.mat2[order(-q.mat2$yfit2),]
    quantile1.mle <- cumsum(q.mat1$w1)/n
    quantile2.mle <- cumsum(q.mat2$w2)/n
    indices1 <- which((quantile1.mle<=q+0.05) & (quantile1.mle>=q))
    indices2 <- which((quantile2.mle<=q+0.05) & (quantile2.mle>=q))
    if (length(indices1) == 0) indices1 <- which.min(abs(quantile1.mle - q))
    if (length(indices2) == 0) indices2 <- which.min(abs(quantile2.mle - q))
    p01 <- max(q.mat1[indices1,"yfit1"])
    p02 <- max(q.mat2[indices2,"yfit2"])
    
    num1 <- sum((yfit1*fhat1)[yfit1>=p01])
    num2 <- sum((yfit2*fhat2)[yfit2>=p02])
    denom1 <- sum(yfit1*fhat1)
    denom2 <- sum(yfit2*fhat2)
    dT_beta[i] <- (num1/denom1-num2/denom2)/(2*epsilon_beta[i])
  }
  
  #Calculate influence function for T(Risk distribution at F_inverse(1-q))
  phi <- (p0_hat*(1-q)-yhat.mle*(1-pcf)-(p0_hat-yhat.mle)*as.numeric(yhat.mle<=p0_hat))/denom_pcf
  
  # calcualte the variance of pcf
  a <- rep(as.vector(apply(h1, 2, function(x) x %*% dT_beta)), c(strata_mat[4, ], strata_mat[3, ]))
  b <- rep(as.vector(apply(h2, 2, function(x) x %*% dT_beta)), dat2.mle$cases+dat2.mle$conts)
  c <- rep(-phi, dat2.mle$cases+dat2.mle$conts)
  temp1 <- c(a, b)
  temp2 <- c(rep(0,length(a)), c)
  var_pcf <- t(temp1+temp2) %*% (temp1+temp2)/n^2
  
  return(list(pcf=pcf, var_pcf=var_pcf))
}

Dat_pcf_mle_old <- function(q, data, fullFit_list, X){
  #q: threshold for calculating pcf
  #fullFit_list: generated by Dat_fullFit(data)
  h1 <- fullFit_list$h1
  h0 <- fullFit_list$h0
  yhat.full <- fullFit_list$yhat.full
  beta.full <- fullFit_list$beta.full
  numbeta <- length(beta.full)
  epsilon_beta <- abs(beta_true[1:4])/5
  #calculate pcf(q)
  quantile.full <- quantile(yhat.full, probs=c(0,1-q,1))
  
  p0_hat <- quantile.full[2]
  #sum(yhat.full==p0_hat)
  #num_pcf <- sum(yhat.full[yhat.full>=p0_hat])
  yhat.full.sort <- sort(yhat.full)
  num_pcf <- sum(yhat.full.sort[(round(n*(1-q))):n])
  denom_pcf <- sum(yhat.full)
  pcf <- num_pcf/denom_pcf
  
  ## numerical method for dPCF/dbeta
  dT_beta<- numeric(numbeta)
  yfit1 <- numeric(nrow(data))
  yfit2 <- numeric(nrow(data))
  for (i in 1:numbeta){
    tmp1 <- beta.full
    tmp2 <- beta.full
    tmp1[i] <- beta.full[i] + epsilon_beta[i]
    tmp2[i] <- beta.full[i] - epsilon_beta[i]
    yfit1 <- exp(X %*% tmp1)/(1 + exp(X %*% tmp1))
    yfit2 <-  exp(X %*% tmp2)/(1 + exp(X %*% tmp2))
    #quantile1 <- quantile(yfit1, probs=c(0,1-q,1))
    #quantile2 <- quantile(yfit2, probs=c(0,1-q,1))
    #p01 <- quantile1[2]
    #p02 <- quantile2[2]
    
    #num1 <- sum(yfit1[yfit1>=p01])
    #num2 <- sum(yfit2[yfit2>=p02])
    yfit1.sort <- sort(yfit1)
    yfit2.sort <- sort(yfit2)
    num1 <- sum(yfit1.sort[(round(n*(1-q))):n])
    num2 <- sum(yfit2.sort[(round(n*(1-q))):n])
    denom1 <- sum(yfit1)
    denom2 <- sum(yfit2)
    dT_beta[i] <- (num1/denom1-num2/denom2)/(2*epsilon_beta[i])
  }
  
  #Calculate influence function for T(Risk distribution at F_inverse(1-q))
  phi <- (p0_hat*(1-q)-yhat.full*(1-pcf)-(p0_hat-yhat.full)*as.numeric(yhat.full<=p0_hat))/(denom_pcf/n)
  
  # calculate influence function for PCF at p0_hat
  h1_pcf <- dT_beta %*% h1 - phi
  h0_pcf <- dT_beta %*% h0 - phi
  
  emp_cov_pcf <- sum((h1_pcf)^2*data$y, (h0_pcf)^2*(1-data$y))
  var_pcf <- emp_cov_pcf/n^2
  return(list(pcf=pcf, sq_var_pcf=sqrt(var_pcf)))
}
# 2.2 calculate pnf by fitting the maximum likelihood model (新增)
Dat_pnf_mle <- function(p, data_list, mleFit_list){
  #p: threshold value for calculating PNF
  #data_list: generated by Dat_format("MLE");
  fdat.mle <- data_list$fdat.mle
  dat1.mle <- data_list$dat1.mle
  dat2.mle <- data_list$dat2.mle
  
  #mleFit_list: generated by Dat_mleFit(data_list)
  fhat.mle <- mleFit_list$f.mle
  yhat.mle <- mleFit_list$yhat.mle
  beta.mle <- mleFit_list$beta.mle
  numbeta <- length(beta.mle) # 从模型中获取beta数量
  # influence function for odds ratio
  h1 <- mleFit_list$h1
  h2 <- mleFit_list$h2
  strata_mat <- mleFit_list$strata_mat
  df_beta <- mleFit_list$df_beta
  
  #calculate pnf(q)
  p.mat <- data.frame(cbind(yhat.mle, fhat.mle*n))
  names(p.mat) <- c("yhat.mle", "w")
  p.mat <- p.mat[order(-p.mat$yhat.mle),]
  num.mle <- cumsum(p.mat$yhat.mle*p.mat$w)
  denom.mle <- sum(p.mat$yhat.mle*p.mat$w)
  ratio.mle <- num.mle/denom.mle
  indices <- which((ratio.mle<=p+0.05) & (ratio.mle>=p))
  if (length(indices) == 0) indices <- which.min(abs(ratio.mle - p))
  r_hat <- max(p.mat[indices,"yhat.mle"])
  
  # calculate pnf
  pnf <- sum(fhat.mle[yhat.mle>=r_hat])
  
  # numerically calcualte dPNF/dbeta
  # 注意：epsilon_beta需要从全局环境中获取，或者作为参数传入
  dT_beta<- numeric(numbeta)
  yfit1 <- numeric(nrow(dat2.mle))
  yfit2 <- numeric(nrow(dat2.mle))
  fhat1 <- numeric(nrow(dat2.mle))
  fhat2 <- numeric(nrow(dat2.mle))
  X <- cbind(rep(1,nrow(dat2.mle)), dat2.mle$x1, dat2.mle$x2, dat2.mle$x3, dat2.mle$z) #Design matrix
  for (i in 1:numbeta){
    tmp1 <- beta.mle
    tmp2 <- beta.mle
    tmp1[i] <- beta.mle[i] + epsilon_beta[i]
    tmp2[i] <- beta.mle[i] - epsilon_beta[i]
    yfit1 <- exp(X %*% tmp1)/(1 + exp(X %*% tmp1))
    yfit2 <-  exp(X %*% tmp2)/(1 + exp(X %*% tmp2))
    fhat1 <- fhat.mle + df_beta[i,]*epsilon_beta[i]
    fhat2 <- fhat.mle - df_beta[i,]*epsilon_beta[i]
    p.mat1 <- data.frame(cbind(yfit1, fhat1*n))
    p.mat2 <- data.frame(cbind(yfit2, fhat2*n))
    names(p.mat1) <- c("yfit1", "w1")
    names(p.mat2) <- c("yfit2", "w2")
    p.mat1 <- p.mat1[order(-p.mat1$yfit1),]
    p.mat2 <- p.mat2[order(-p.mat2$yfit2),]
    
    num1 <- cumsum(p.mat1$yfit1*p.mat1$w1)
    num2 <- cumsum(p.mat2$yfit2*p.mat2$w2)
    denom1 <- sum(p.mat1$yfit1*p.mat1$w1)
    denom2 <- sum(p.mat2$yfit2*p.mat2$w2)
    ratio1 <- num1/denom1
    ratio2 <- num2/denom2
    indices1 <- which((ratio1<=p+0.05) & (ratio1>=p))
    indices2 <- which((ratio2<=p+0.05) & (ratio2>=p))
    if (length(indices1) == 0) indices1 <- which.min(abs(ratio1 - p))
    if (length(indices2) == 0) indices2 <- which.min(abs(ratio2 - p))
    r1 <- max(p.mat1[indices1,"yfit1"])
    r2 <- max(p.mat2[indices2,"yfit2"])
    
    pnf1 <- sum(fhat1[yfit1>=r1])
    pnf2 <- sum(fhat2[yfit2>=r2])
    dT_beta[i] <- (pnf1-pnf2)/(2*epsilon_beta[i])
  }
  
  #Calculate influence function for T(Risk distribution at G_inverse(1-p))
  phi <- as.numeric(yhat.mle<=r_hat) + yhat.mle/r_hat*((1-p)-as.numeric(yhat.mle<=r_hat))-(1-pnf)
  
  # calcualte the variance of pnf
  a <- rep(as.vector(apply(h1, 2, function(x) x %*% dT_beta)), c(strata_mat[4, ], strata_mat[3, ]))
  b <- rep(as.vector(apply(h2, 2, function(x) x %*% dT_beta)), (dat2.mle$cases+dat2.mle$conts))
  c <- rep(-phi, (dat2.mle$cases+dat2.mle$conts))
  temp1 <- c(a, b)
  temp2 <- c(rep(0,length(a)), c)
  var_pnf <- t(temp1+temp2) %*% (temp1+temp2)/n^2
  
  return(list(pnf=pnf, var_pnf=var_pnf))
}
Dat_pnf_mle_old <- function(p, data, fullFit_list, X){
  #p: threshold for calculating pnf
  #fullFit_list: generated by Dat_fullFit(data)
  h1 <- fullFit_list$h1
  h0 <- fullFit_list$h0
  yhat.full <- fullFit_list$yhat.full
  beta.full <- fullFit_list$beta.full
  numbeta <- length(beta.full)
  epsilon_beta <- abs(beta_true[1:4])/5
  #calculate pnf(p)
  denom.full <- sum(yhat.full)
  yhat.full.sort <- sort(yhat.full, decreasing=T)
  num.full <- cumsum(yhat.full.sort)
  ratio.full <- num.full/denom.full
  indices <- which((ratio.full<=p+0.05) & (ratio.full>=p))
  r_hat <- max(yhat.full.sort[indices])
  
  #pnf <- sum(yhat.full>=r_hat)/n
  pnf <- as.numeric(indices[1]/n)
  ## numerical method for dPNF/dbeta
  dT_beta<- numeric(numbeta)
  yfit1 <- numeric(nrow(data))
  yfit2 <- numeric(nrow(data))
  for (i in 1:numbeta){
    tmp1 <- beta.full
    tmp2 <- beta.full
    tmp1[i] <- beta.full[i] + epsilon_beta[i]
    tmp2[i] <- beta.full[i] - epsilon_beta[i]
    yfit1 <- exp(X %*% tmp1)/(1 + exp(X %*% tmp1))
    yfit2 <-  exp(X %*% tmp2)/(1 + exp(X %*% tmp2))
    
    denom1 <- sum(yfit1)
    denom2 <- sum(yfit2)
    yfit1.sort <- sort(yfit1, decreasing=T)
    yfit2.sort <- sort(yfit2, decreasing=T)
    num1 <- cumsum(yfit1.sort)
    num2 <- cumsum(yfit2.sort)
    ratio1 <- num1/denom1
    ratio2 <- num2/denom2
    indices1 <- which((ratio1<=p+0.05) & (ratio1>=p))
    indices2 <- which((ratio2<=p+0.05) & (ratio2>=p))
    r1 <- max(yfit1.sort[indices1])
    r2 <- max(yfit2.sort[indices2])
    
    #pnf1 <- sum(yfit1>=r1)/n
    #pnf2 <- sum(yfit2>=r2)/n
    pnf1 <- as.numeric(indices1[1]/n)
    pnf2 <- as.numeric(indices2[1]/n)
    dT_beta[i] <- (pnf1-pnf2)/(2*epsilon_beta[i])
  }
  
  #Calculate influence function for T(Risk distribution at G_inverse(1-p))
  phi <- as.numeric(yhat.full<=r_hat) + yhat.full/r_hat*((1-p)-as.numeric(yhat.full<=r_hat))-(1-pnf)
  
  # calculate influence function for PCF at p0_hat
  h1_pnf <- dT_beta %*% h1 - phi
  h0_pnf <- dT_beta %*% h0 - phi
  
  emp_cov_pnf <- sum((h1_pnf)^2*data$y, (h0_pnf)^2*(1-data$y))
  var_pnf <- emp_cov_pnf/n^2
  return(list(pnf=pnf, sq_var_pnf=sqrt(var_pnf)))
}

calculate_empirical_auc_variance <- function(auc_results_matrix) {
