# 2.4 SNB 计算函数 (全抽样 / 旧模型)
# ==============================================================================
Dat_snb_mle_old <- function(t, dat, fullFit_list, X){
  n <- nrow(dat)
  yhat <- fullFit_list$yhat.full
  h_beta_all <- fullFit_list$h_beta_all # 所有样本的 Beta 影响函数 (p x n)
  
  # 1. 点估计
  pi_est <- mean(yhat)
  ind <- as.numeric(yhat >= t)
  
  tpr_est <- sum(yhat * ind) / sum(yhat)
  fpr_est <- sum((1 - yhat) * ind) / sum(1 - yhat)
  
  weight <- (1 - pi_est) / pi_est * (t / (1 - t))
  snb_est <- tpr_est - weight * fpr_est
  
  # 2. 数值微分 dSNB/dbeta
  beta.full <- fullFit_list$beta.full
  numbeta <- length(beta.full)
  dSNB_beta <- numeric(numbeta)
  epsilon_beta <- abs(beta.full) / 1000
  epsilon_beta[epsilon_beta == 0] <- 0.001
  
  for(i in 1:numbeta){
    b_p <- beta.full; b_p[i] <- b_p[i] + epsilon_beta[i]
    b_m <- beta.full; b_m[i] <- b_m[i] - epsilon_beta[i]
    
    y_p <- exp(X %*% b_p) / (1 + exp(X %*% b_p))
    y_m <- exp(X %*% b_m) / (1 + exp(X %*% b_m))
    
    pi_p <- mean(y_p)
    tpr_p <- sum(y_p * (y_p >= t)) / sum(y_p)
    fpr_p <- sum((1-y_p) * (y_p >= t)) / sum(1-y_p)
    w_p <- (1-pi_p)/pi_p * (t/(1-t))
    snb_p <- tpr_p - w_p * fpr_p
    
    pi_m <- mean(y_m)
    tpr_m <- sum(y_m * (y_m >= t)) / sum(y_m)
    fpr_m <- sum((1-y_m) * (y_m >= t)) / sum(1-y_m)
    w_m <- (1-pi_m)/pi_m * (t/(1-t))
    snb_m <- tpr_m - w_m * fpr_m
    
    dSNB_beta[i] <- (snb_p - snb_m) / (2 * epsilon_beta[i])
  }
  
  # 3. 计算经验分布下的影响函数 (Phi)
  phi_tpr <- yhat * (ind - tpr_est) / pi_est
  phi_fpr <- (1 - yhat) * (ind - fpr_est) / (1 - pi_est)
  phi_pi <- (yhat - pi_est)
  
  term_pi <- (weight * fpr_est / (pi_est * (1 - pi_est))) * phi_pi
  
  phi_snb <- phi_tpr - weight * phi_fpr + term_pi
  
  # 4. 总影响函数
  # h_beta_all 是 (p x n) 矩阵, t(h_beta_all) 是 (n x p)
  h_snb <- as.vector(t(h_beta_all) %*% dSNB_beta) + phi_snb
  
  var_snb <- sum(h_snb^2) / n^2 # 或 var(h_snb)/n
  
  return(list(snb = snb_est, var_snb = var_snb))
}
